#define rs (k<<1|1)
#define mid ((l+r)>>1)
using NP std;
NP phigrOS
{
    il ll read()
    {
        ll x=0,f=1;char ch=gc();
        wh(ch<'0'||ch>'9'){if(ch=='-')f=-1;ch=getchar();}
        wh(ch>='0'&&ch<='9'){x=x*10+ch-'0';ch=gc();}
        return x*f;
    }
    void write(ll x)
    {
        if(x<0)pc('-'),x=-x;
        if(x>9)write(x/10);
        pc(x%10+'0');
    }
    void writeln(ll x)
    {
        write(x);
        puts("");
        return;
    }
}
using NP phigrOS;
CI MAXN=1e5+5;
int n,f[MAXN][5];
vector<int> g[MAXN];
void dfs(int u,int fa)
{
	f[u][1]=1;
	int ok=1,mi=llinf;
	FOI(s,g[u])
	{
		if(s==fa)continue;
		dfs(s,u);
		f[u][1]+=min({f[s][1],f[s][2],f[s][3]});
		f[u][2]+=min(f[s][1],f[s][3]);
		f[u][3]+=min(f[s][1],f[s][3]);
		if(f[s][3]>f[s][1])ok=0;
		mi=min(mi,f[s][1]-f[s][3]);
	}
	if(ok)f[u][3]+=mi;
}
signed main(void)
{

    //freopen(".in","r",stdin);
