	ios::sync_with_stdio(0);
	cin.tie(0);
	cin>>n;
	FOR(i,2,n)
	{
		int u,v;
		cin>>u>>v;
		g[u].pb(v);
		g[v].pb(u);
	}
	dfs(1,0);
	cout<<min(f[1][1],f[1][3]);
    return false;
}
